154→        const fileTime = new Date(
155→          `${match[1]}T${match[2]}:${match[3]}:${match[4]}Z`,
156→        );
157→        // Accept files created around or after the run started
158→        return fileTime.getTime() >= runStartTime.getTime() - MAX_LOG_AGE_MS;
159→      });
