170→/**
171→ * Build a structured response from a parsed RunLog
172→ */
173→export function buildStructuredResponse(
174→  runLog: RunLog,
175→  rawOutput: string,
176→  overallStatus: "success" | "failure",
177→  exitCode?: number | null,
178→  errorOutput?: string,
179→): RunToolResponse {
180→  const issues: RunToolIssueSummary[] = runLog.issues.map((issue) => {
181→    // Find QA verdict from phase logs
182→    const qaPhase = issue.phases.find((p) => p.phase === "qa");
183→    const verdict = qaPhase?.verdict;
184→
185→    return {
186→      issueNumber: issue.issueNumber,
187→      status: issue.status,
188→      phases: issue.phases.map((p) => ({
189→        phase: p.phase,
190→        status: p.status,
191→        durationSeconds: p.durationSeconds,
192→      })),
193→      ...(verdict ? { verdict } : {}),
194→      durationSeconds: issue.totalDurationSeconds,
195→    };
196→  });
197→
198→  const phasesRan = [
199→    ...new Set(runLog.issues.flatMap((i) => i.phases.map((p) => p.phase))),
200→  ].join(",");
201→
202→  const response: RunToolResponse = {
203→    status: overallStatus,
204→    ...(exitCode != null && exitCode !== 0 ? { exitCode } : {}),
205→    issues,
206→    summary: {
207→      total: runLog.summary.totalIssues,
208→      passed: runLog.summary.passed,
209→      failed: runLog.summary.failed,
210→      durationSeconds: runLog.summary.totalDurationSeconds,
211→    },
212→    phases: phasesRan || runLog.config.phases.join(","),
213→    rawOutput: rawOutput.slice(-MAX_RAW_OUTPUT),
214→    ...(errorOutput ? { error: errorOutput.slice(-1000) } : {}),
215→  };
216→
217→  return enforceResponseSizeLimit(response);
218→}
219→
220→/**
221→ * Enforce response size limit by progressively truncating rawOutput.
222→ * Uses Buffer.byteLength for accurate UTF-8 byte measurement.
223→ */
224→function enforceResponseSizeLimit(response: RunToolResponse): RunToolResponse {
225→  let json = JSON.stringify(response);
226→  let byteLength = Buffer.byteLength(json, "utf-8");
227→
228→  if (byteLength <= MAX_RESPONSE_SIZE) {
229→    return response;
230→  }
231→
232→  // Progressively truncate rawOutput to fit
233→  const rawOutput = response.rawOutput || "";
234→  if (rawOutput.length > 0) {
235→    const excess = byteLength - MAX_RESPONSE_SIZE;
236→    // Over-trim slightly: multi-byte chars mean char count < byte count
237→    const newLength = Math.max(0, rawOutput.length - excess - 200);
238→
239→    response.rawOutput =
240→      newLength > 0 ? rawOutput.slice(-newLength) : undefined;
241→
242→    json = JSON.stringify(response);
243→    byteLength = Buffer.byteLength(json, "utf-8");
244→  }
245→
246→  // If still too large (structured data itself is huge), truncate error field
247→  if (byteLength > MAX_RESPONSE_SIZE && response.error) {
248→    const excess = byteLength - MAX_RESPONSE_SIZE;
249→    const newLength = Math.max(0, response.error.length - excess - 200);
250→    response.error =
251→      newLength > 0 ? response.error.slice(-newLength) : undefined;
252→  }
253→
254→  return response;
255→}
