  1→/**
  2→ * sequant_status MCP tool
  3→ *
  4→ * Get current workflow state for an issue.
  5→ */
  6→
  7→import { z } from "zod";
  8→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  9→import { StateManager } from "../../lib/workflow/state-manager.js";
 10→import { isRunning } from "../run-registry.js";
 11→import {
 12→  reconcileState,
 13→  getNextActionHint,
 14→} from "../../lib/workflow/reconcile.js";
 15→
 16→export function registerStatusTool(server: McpServer): void {
 17→  server.registerTool(
 18→    "sequant_status",
 19→    {
 20→      title: "Sequant Status",
 21→      description:
 22→        "Get the current workflow state, phase progress, and QA verdict for a tracked issue. " +
 23→        "Reconciles with GitHub on every call for accurate status. " +
 24→        "Use this to check whether an issue needs work before calling sequant_run. " +
 25→        "Returns isRunning: true when a sequant_run is actively executing — " +
 26→        "poll every 5-10 seconds during active runs for phase-level progress updates.",
 27→      annotations: {
 28→        readOnlyHint: true,
 29→        idempotentHint: true,
 30→      },
 31→      inputSchema: {
 32→        issue: z.number().describe("GitHub issue number to check status for"),
 33→      },
 34→    },
 35→    async ({ issue }) => {
 36→      if (!issue || issue <= 0) {
 37→        return {
 38→          content: [
 39→            {
 40→              type: "text" as const,
 41→              text: JSON.stringify({
 42→                error: "INVALID_INPUT",
 43→                message: "A valid issue number is required",
 44→              }),
 45→            },
 46→          ],
 47→          isError: true,
 48→        };
 49→      }
 50→
 51→      try {
 52→        const stateManager = new StateManager();
 53→
 54→        // Reconcile state with GitHub before reading
 55→        const reconcileResult = await reconcileState({ stateManager });
 56→        stateManager.clearCache();
 57→
 58→        const issueState = await stateManager.getIssueState(issue);
 59→
 60→        if (!issueState) {
 61→          return {
 62→            content: [
 63→              {
 64→                type: "text" as const,
 65→                text: JSON.stringify({
 66→                  issue,
 67→                  status: "not_tracked",
 68→                  isRunning: isRunning(issue),
 69→                  lastSynced: reconcileResult.lastSynced,
 70→                  githubReachable: reconcileResult.githubReachable,
 71→                  message: `Issue #${issue} is not currently tracked in workflow state`,
 72→                }),
 73→              },
 74→            ],
 75→          };
 76→        }
 77→
 78→        return {
 79→          content: [
 80→            {
 81→              type: "text" as const,
 82→              text: JSON.stringify({
 83→                issue,
 84→                title: issueState.title,
 85→                status: issueState.status,
 86→                isRunning: isRunning(issue),
 87→                currentPhase: issueState.currentPhase,
 88→                phases: issueState.phases,
 89→                worktree: issueState.worktree,
 90→                pr: issueState.pr,
 91→                lastActivity: issueState.lastActivity,
 92→                nextAction: getNextActionHint(issueState),
 93→                lastSynced: reconcileResult.lastSynced,
 94→                githubReachable: reconcileResult.githubReachable,
 95→                warnings: reconcileResult.warnings
 96→                  .filter((w) => w.issueNumber === issue)
 97→                  .map((w) => w.description),
 98→              }),
 99→            },
100→          ],
101→        };
102→      } catch (error) {
103→        return {
104→          content: [
105→            {
106→              type: "text" as const,
107→              text: JSON.stringify({
108→                error: "STATE_ERROR",
109→                message: error instanceof Error ? error.message : String(error),
110→              }),
111→            },
112→          ],
113→          isError: true,
114→        };
115→      }
116→    },
117→  );
118→}
