 58→/**
 59→ * Resolve the CLI binary path to avoid nested npx version mismatches (#389).
 60→ *
 61→ * Priority:
 62→ * 1. process.argv[1] — the script currently running (works for npx, global, local node)
 63→ * 2. __dirname-relative resolution — fallback for bundled/compiled entry points
 64→ * 3. "npx" + "sequant" — last resort if nothing else resolves
 65→ *
 66→ * Returns [command, prefixArgs] where the full invocation is:
 67→ *   spawnAsync(command, [...prefixArgs, "run", ...userArgs])
 68→ */
 69→export function resolveCliBinary(): [string, string[]] {
 70→  // Try process.argv — most reliable across npx, global install, and local node
 71→  const nodeExe = process.argv[0];
 72→  const scriptPath = process.argv[1];
 73→
 74→  if (scriptPath && existsSync(scriptPath)) {
 75→    // If the entry point is a .ts file (e.g. running via `npx tsx bin/cli.ts serve`),
 76→    // the child process won't have tsx's loader hooks. Prefer the compiled dist output,
 77→    // or fall through to use tsx explicitly.
 78→    if (!scriptPath.endsWith(".ts")) {
 79→      return [nodeExe, [scriptPath]];
 80→    }
 81→
 82→    // Try compiled dist equivalent: bin/cli.ts → dist/bin/cli.js
 83→    const distPath = resolve(
 84→      dirname(scriptPath),
 85→      "..",
 86→      "dist",
 87→      "bin",
 88→      "cli.js",
 89→    );
 90→    if (existsSync(distPath)) {
 91→      return [process.execPath, [distPath]];
 92→    }
 93→
 94→    // Use tsx to run the .ts file directly
 95→    return ["npx", ["tsx", scriptPath]];
 96→  }
 97→
 98→  // Fallback: resolve relative to this file's location (dist/src/mcp/tools/run.js → dist/bin/cli.js)
 99→  const cliPath = resolve(dirname(__dirname), "..", "..", "bin", "cli.js");
100→  if (existsSync(cliPath)) {
101→    return [process.execPath, [cliPath]];
102→  }
103→
104→  // Last resort: fall back to npx (original behavior)
105→  return ["npx", ["sequant"]];
106→}
