108→/**
109→ * Resolve the log directory path (project-level or user-level)
110→ */
111→function resolveLogDir(): string {
112→  const projectPath = LOG_PATHS.project;
113→  if (existsSync(projectPath)) {
114→    return projectPath;
115→  }
116→
117→  const userPath = LOG_PATHS.user.replace("~", homedir());
118→  if (existsSync(userPath)) {
119→    return userPath;
120→  }
121→
122→  return projectPath;
123→}
