303→export function registerRunTool(server: McpServer): void {
304→  server.registerTool(
305→    "sequant_run",
306→    {
307→      title: "Sequant Run",
308→      description:
309→        "Execute structured AI workflow phases for GitHub issues. " +
310→        "Runs spec (plan) → exec (implement) → qa (review) in sequence, creating worktrees and PRs. " +
311→        "Long-running: up to 30 minutes per issue. Returns structured JSON with per-issue phase results. " +
312→        "Check sequant_status first to avoid re-running completed issues. " +
313→        "Example: {issues: [123], phases: 'spec,exec'}",
314→      annotations: {
315→        readOnlyHint: false,
316→        destructiveHint: false,
317→        idempotentHint: false,
318→        openWorldHint: true,
319→      },
320→      inputSchema: runToolInputSchema,
321→    },
322→    (async (
323→      {
324→        issues,
325→        phases,
326→        qualityLoop,
327→        agent,
328→      }: {
329→        issues: number[];
330→        phases?: string;
331→        qualityLoop?: boolean;
332→        agent?: string;
333→      },
334→      extra: { signal: AbortSignal },
335→    ) => {
336→      if (!issues || issues.length === 0) {
337→        return {
338→          content: [
339→            {
340→              type: "text" as const,
341→              text: JSON.stringify({
342→                error: "INVALID_INPUT",
343→                message: "At least one issue number is required",
344→              }),
345→            },
346→          ],
347→          isError: true,
348→        };
349→      }
350→
351→      // Resolve CLI binary to avoid nested npx version mismatch (#389)
352→      const [command, prefixArgs] = resolveCliBinary();
353→
354→      // Build command arguments
355→      const args = [...prefixArgs, "run", ...issues.map(String)];
356→      if (phases) {
357→        args.push("--phases", phases);
358→      }
359→      if (qualityLoop) {
360→        args.push("--quality-loop");
361→      }
362→      if (agent) {
363→        args.push("--agent", agent);
364→      }
365→      args.push("--log-json");
366→
367→      const phasesStr = phases || "spec,exec,qa";
368→      const runStartTime = new Date();
369→
370→      // Register all issues as active runs for real-time status polling
371→      for (const issue of issues) {
372→        registerRun(issue);
373→      }
374→
375→      try {
376→        const result = await spawnAsync(command, args, {
377→          timeout: 1800000, // 30 min default
378→          env: {
379→            ...process.env,
380→            SEQUANT_ORCHESTRATOR: "mcp-server",
381→          },
382→          signal: extra.signal,
383→        });
384→
385→        const stdout = result.stdout || "";
386→        const stderr = result.stderr || "";
387→        const overallStatus: "success" | "failure" =
388→          result.exitCode === 0 ? "success" : "failure";
389→
390→        // Try to read structured log file for rich per-issue data
391→        const runLog = await readLatestRunLog(runStartTime);
392→
393→        let response: RunToolResponse;
394→        if (runLog) {
395→          response = buildStructuredResponse(
396→            runLog,
397→            stdout,
398→            overallStatus,
399→            result.exitCode,
400→            stderr || undefined,
401→          );
402→        } else {
403→          // Fallback: no log file available
404→          response = buildFallbackResponse(
405→            stdout,
406→            issues,
407→            overallStatus,
408→            phasesStr,
409→            result.exitCode,
410→            stderr || undefined,
411→          );
412→        }
413→
414→        return {
415→          content: [
416→            {
417→              type: "text" as const,
418→              text: JSON.stringify(response),
419→            },
420→          ],
421→          ...(result.exitCode !== 0 ? { isError: true } : {}),
422→        };
423→      } catch (error) {
424→        return {
425→          content: [
426→            {
427→              type: "text" as const,
428→              text: JSON.stringify({
429→                error: "EXECUTION_ERROR",
430→                message: error instanceof Error ? error.message : String(error),
431→              }),
432→            },
433→          ],
434→          isError: true,
435→        };
436→      } finally {
437→        for (const issue of issues) {
438→          unregisterRun(issue);
439→        }
440→      }
441→    }) as Parameters<typeof server.registerTool>[2],
442→  );
443→}
