445→export interface SpawnResult {
446→  exitCode: number | null;
447→  stdout: string;
448→  stderr: string;
449→}
450→
451→export interface SpawnOptions {
452→  timeout: number;
453→  env?: NodeJS.ProcessEnv;
454→  signal?: AbortSignal;
455→}
