457→/** @internal Exported for testing only */
458→export function spawnAsync(
459→  command: string,
460→  args: string[],
461→  options: SpawnOptions,
462→): Promise<SpawnResult> {
463→  return new Promise((resolve, reject) => {
464→    let stdout = "";
465→    let stderr = "";
466→    let settled = false;
467→
468→    const proc = spawn(command, args, {
469→      stdio: ["pipe", "pipe", "pipe"],
470→      env: options.env,
471→      detached: true,
472→    });
473→
474→    const settle = (
475→      outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
476→    ) => {
477→      if (settled) return;
478→      settled = true;
479→      clearTimeout(timeoutId);
480→      options.signal?.removeEventListener("abort", onAbort);
481→      if (outcome.ok) {
482→        resolve(outcome.result);
483→      } else {
484→        reject(outcome.error);
485→      }
486→    };
487→
488→    const timeoutId = setTimeout(() => {
489→      killProcessGroup(proc);
490→      settle({
491→        ok: false,
492→        error: new Error(`Process timed out after ${options.timeout}ms`),
493→      });
494→    }, options.timeout);
495→
496→    const onAbort = () => {
497→      killProcessGroup(proc);
498→      settle({ ok: false, error: new Error("Cancelled by client") });
499→    };
500→
501→    if (options.signal) {
502→      if (options.signal.aborted) {
503→        killProcessGroup(proc);
504→        clearTimeout(timeoutId);
505→        reject(new Error("Cancelled by client"));
506→        return;
507→      }
508→      options.signal.addEventListener("abort", onAbort, { once: true });
509→    }
510→
511→    proc.stdout.on("data", (data: Buffer) => {
512→      stdout += data.toString();
513→    });
514→
515→    proc.stderr.on("data", (data: Buffer) => {
516→      stderr += data.toString();
517→    });
518→
519→    proc.on("error", (err: NodeJS.ErrnoException) => {
520→      if (err.code === "ENOENT") {
521→        settle({
522→          ok: false,
523→          error: new Error(
524→            `Command not found: ${command}. Ensure it is installed and in PATH.`,
525→          ),
526→        });
527→      } else {
528→        settle({
529→          ok: false,
530→          error: new Error(`Failed to spawn process: ${err.message}`),
531→        });
532→      }
533→    });
534→
535→    proc.on("close", (code: number | null) => {
536→      settle({ ok: true, result: { exitCode: code, stdout, stderr } });
537→    });
538→  });
539→}
