541→const SIGKILL_GRACE_MS = 5000;
542→
543→function killProcessGroup(proc: ReturnType<typeof spawn>): void {
544→  let exited = false;
545→  proc.on("close", () => {
546→    exited = true;
547→  });
548→
549→  sendSignal(proc, "SIGTERM");
550→
551→  setTimeout(() => {
552→    if (!exited) {
553→      sendSignal(proc, "SIGKILL");
554→    }
555→  }, SIGKILL_GRACE_MS).unref();
556→}
557→
558→function sendSignal(
559→  proc: ReturnType<typeof spawn>,
560→  signal: NodeJS.Signals,
561→): void {
562→  try {
563→    if (proc.pid) {
564→      process.kill(-proc.pid, signal);
565→    }
566→  } catch {
567→    // Process group may already be gone — fall back to direct kill
568→    if (!proc.killed) {
569→      proc.kill(signal);
570→    }
571→  }
572→}
