 51→/**
 52→ * Manages writing structured run logs to disk
 53→ */
 54→export class LogWriter {
 55→  private runLog: Omit<RunLog, "endTime"> | null = null;
 56→  /** Active issues being tracked concurrently, keyed by issue number */
 57→  private activeIssues: Map<number, Partial<IssueLog>> = new Map();
 58→  /** @deprecated Single-issue slot for backwards compatibility — use activeIssues */
 59→  private currentIssue: Partial<IssueLog> | null = null;
 60→  private logPath: string;
 61→  private writeToUserLogs: boolean;
 62→  private verbose: boolean;
 63→  private rotation: RotationSettings;
 64→  private startCommit?: string;
 65→
 66→  constructor(options: LogWriterOptions = {}) {
 67→    this.logPath = options.logPath ?? LOG_PATHS.project;
 68→    this.writeToUserLogs = options.writeToUserLogs ?? false;
 69→    this.verbose = options.verbose ?? false;
 70→    this.rotation = options.rotation ?? DEFAULT_ROTATION_SETTINGS;
 71→    this.startCommit = options.startCommit;
 72→  }
 73→
 74→  /**
 75→   * Initialize a new run log
 76→   *
 77→   * @param config - Run configuration
 78→   */
 79→  async initialize(config: RunConfig): Promise<void> {
 80→    this.runLog = createEmptyRunLog(config, { startCommit: this.startCommit });
 81→
 82→    // Ensure log directory exists
 83→    await this.ensureLogDirectory(this.logPath);
 84→
 85→    if (this.writeToUserLogs) {
 86→      const userPath = LOG_PATHS.user.replace("~", os.homedir());
 87→      await this.ensureLogDirectory(userPath);
 88→    }
 89→
 90→    if (this.verbose && this.runLog) {
 91→      console.log(`📝 Log initialized: ${this.runLog.runId}`);
 92→    }
 93→  }
 94→
 95→  /**
 96→   * Start logging a new issue
 97→   *
 98→   * @param issueNumber - GitHub issue number
 99→   * @param title - Issue title
100→   * @param labels - Issue labels
101→   */
102→  startIssue(issueNumber: number, title: string, labels: string[]): void {
103→    if (!this.runLog) {
104→      throw new Error("LogWriter not initialized. Call initialize() first.");
105→    }
106→
107→    const issueData: Partial<IssueLog> = {
108→      issueNumber,
109→      title,
110→      labels,
111→      phases: [],
112→      status: "success" as IssueStatus,
113→      totalDurationSeconds: 0,
114→    };
115→
116→    this.activeIssues.set(issueNumber, issueData);
117→    // Keep currentIssue in sync for callers that don't pass issueNumber
118→    this.currentIssue = issueData;
119→
120→    if (this.verbose) {
121→      console.log(`📝 Started logging issue #${issueNumber}`);
122→    }
123→  }
124→
125→  /**
126→   * Log a completed phase
127→   *
128→   * @param phaseLog - Complete phase log entry
129→   */
130→  logPhase(phaseLog: PhaseLog): void {
131→    // Route to the correct issue by issueNumber, falling back to currentIssue
132→    const issue =
133→      this.activeIssues.get(phaseLog.issueNumber) ?? this.currentIssue;
134→    if (!issue) {
135→      throw new Error(
136→        `No active issue #${phaseLog.issueNumber}. Call startIssue() first.`,
137→      );
138→    }
139→
140→    issue.phases = [...(issue.phases ?? []), phaseLog];
141→
142→    // Update issue status based on phase result
143→    if (phaseLog.status === "failure") {
144→      issue.status = "failure";
145→    } else if (phaseLog.status === "timeout" && issue.status !== "failure") {
146→      issue.status = "partial";
147→    }
148→
149→    if (this.verbose) {
150→      console.log(
151→        `📝 Logged phase: ${phaseLog.phase} (${phaseLog.status}) - ${phaseLog.durationSeconds.toFixed(1)}s`,
152→      );
153→    }
154→  }
155→
156→  /**
157→   * Set PR info on the current issue (call before completeIssue)
158→   */
159→  setPRInfo(prNumber: number, prUrl: string, issueNumber?: number): void {
160→    const issue = issueNumber
161→      ? (this.activeIssues.get(issueNumber) ?? this.currentIssue)
162→      : this.currentIssue;
163→    if (!issue) {
164→      return;
165→    }
166→    issue.prNumber = prNumber;
167→    issue.prUrl = prUrl;
168→  }
169→
170→  /**
171→   * Complete the current issue and add it to the run log
172→   */
173→  completeIssue(issueNumber?: number): void {
174→    if (!this.runLog) {
175→      throw new Error("No run log. Call initialize() first.");
176→    }
177→
178→    // Resolve the issue to complete
179→    const issue = issueNumber
180→      ? this.activeIssues.get(issueNumber)
181→      : this.currentIssue;
182→    if (!issue) {
183→      throw new Error(
184→        issueNumber
185→          ? `No active issue #${issueNumber} to complete.`
186→          : "No current issue to complete.",
187→      );
188→    }
189→
190→    // Calculate total duration from phases
191→    const totalDurationSeconds =
192→      issue.phases?.reduce(
193→        (sum: number, p: PhaseLog) => sum + p.durationSeconds,
194→        0,
195→      ) ?? 0;
196→
197→    const issueLog: IssueLog = {
198→      issueNumber: issue.issueNumber!,
199→      title: issue.title!,
200→      labels: issue.labels!,
201→      status: issue.status!,
202→      phases: issue.phases!,
203→      totalDurationSeconds,
204→      ...(issue.prNumber != null && {
205→        prNumber: issue.prNumber,
206→      }),
207→      ...(issue.prUrl != null && {
208→        prUrl: issue.prUrl,
209→      }),
210→    };
211→
212→    this.runLog.issues.push(issueLog);
213→
214→    // Clean up from activeIssues map
215→    if (issue.issueNumber != null) {
216→      this.activeIssues.delete(issue.issueNumber);
217→    }
218→    // Clear currentIssue if it was the one completed
219→    if (this.currentIssue === issue) {
220→      this.currentIssue = null;
221→    }
222→
223→    if (this.verbose) {
224→      console.log(
225→        `📝 Completed issue #${issueLog.issueNumber} (${issueLog.status})`,
226→      );
227→    }
228→  }
229→
230→  /**
231→   * Finalize the run log and write to disk
232→   *
233→   * Automatically rotates old logs if thresholds are exceeded.
234→   *
235→   * @param options - Optional finalization options
236→   * @param options.endCommit - Git commit SHA at run end (AC-2)
237→   * @returns Path to the written log file
238→   */
239→  async finalize(options?: { endCommit?: string }): Promise<string> {
240→    if (!this.runLog) {
241→      throw new Error("LogWriter not initialized.");
242→    }
243→
244→    // Complete any pending issues (Map-based concurrent tracking)
245→    for (const issueNum of [...this.activeIssues.keys()]) {
246→      this.completeIssue(issueNum);
247→    }
248→    // Fallback: complete legacy currentIssue if not already handled
249→    if (this.currentIssue) {
250→      this.completeIssue();
251→    }
252→
253→    const finalLog = finalizeRunLog(this.runLog, {
254→      endCommit: options?.endCommit,
255→    });
256→    const filename = generateLogFilename(
257→      finalLog.runId,
258→      new Date(finalLog.startTime),
259→    );
260→
261→    // Write to project logs
262→    const projectPath = path.join(this.resolvePath(this.logPath), filename);
263→    await this.writeLogFile(projectPath, finalLog);
264→
265→    // Optionally write to user logs
266→    if (this.writeToUserLogs) {
267→      const userPath = path.join(this.resolvePath(LOG_PATHS.user), filename);
268→      await this.writeLogFile(userPath, finalLog);
269→    }
270→
271→    if (this.verbose) {
272→      console.log(`📝 Log written: ${projectPath}`);
273→    }
274→
275→    // Auto-rotate if needed
276→    if (this.rotation.enabled) {
277→      const result = rotateIfNeeded(this.logPath, this.rotation);
278→      if (result.rotated && this.verbose) {
279→        console.log(
280→          `📝 Rotated ${result.deletedCount} old log(s), reclaimed ${(result.bytesReclaimed / 1024).toFixed(1)} KB`,
281→        );
282→      }
283→    }
284→
285→    return projectPath;
286→  }
287→
288→  /**
289→   * Get the current run log (for inspection)
290→   */
291→  getRunLog(): Omit<RunLog, "endTime"> | null {
292→    return this.runLog;
293→  }
294→
295→  /**
296→   * Get the run ID
297→   */
298→  getRunId(): string | null {
299→    return this.runLog?.runId ?? null;
300→  }
301→
302→  private resolvePath(logPath: string): string {
303→    return logPath.replace("~", os.homedir());
304→  }
305→
306→  private async ensureLogDirectory(logPath: string): Promise<void> {
307→    const resolved = this.resolvePath(logPath);
308→    if (!fs.existsSync(resolved)) {
309→      fs.mkdirSync(resolved, { recursive: true });
310→    }
311→  }
312→
313→  private async writeLogFile(filePath: string, log: RunLog): Promise<void> {
314→    const dir = path.dirname(filePath);
315→    if (!fs.existsSync(dir)) {
316→      fs.mkdirSync(dir, { recursive: true });
317→    }
318→    fs.writeFileSync(filePath, JSON.stringify(log, null, 2));
319→  }
320→}
