148→/**
149→ * Parse dependencies from issue body and labels
150→ * Returns array of issue numbers this issue depends on
151→ */
152→export function parseDependencies(issueNumber: number): number[] {
153→  try {
154→    const result = spawnSync(
155→      "gh",
156→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
157→      { stdio: "pipe" },
158→    );
159→
160→    if (result.status !== 0) return [];
161→
162→    const data = JSON.parse(result.stdout.toString());
163→    const dependencies: number[] = [];
164→
165→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
166→    if (data.body) {
167→      const bodyMatch = data.body.match(
168→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
169→      );
170→      if (bodyMatch) {
171→        for (const match of bodyMatch) {
172→          const numMatch = match.match(/(\d+)/);
173→          if (numMatch) {
174→            dependencies.push(parseInt(numMatch[1], 10));
175→          }
176→        }
177→      }
178→    }
179→
180→    // Parse from labels: "depends-on/123" or "depends-on-123"
181→    if (data.labels && Array.isArray(data.labels)) {
182→      for (const label of data.labels) {
183→        const labelName = label.name || label;
184→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
185→        if (labelMatch) {
186→          dependencies.push(parseInt(labelMatch[1], 10));
187→        }
188→      }
189→    }
190→
191→    return [...new Set(dependencies)]; // Remove duplicates
192→  } catch {
193→    return [];
194→  }
195→}
