  1→/**
  2→ * Phase Spinner - Animated spinner with elapsed time for phase execution
  3→ *
  4→ * Wraps the cli-ui spinner with:
  5→ * - Elapsed time tracking (updates every 5 seconds)
  6→ * - Phase progress indicator (e.g., "spec (1/3)")
  7→ * - Integration with ShutdownManager for graceful cleanup
  8→ *
  9→ * @example
 10→ * ```typescript
 11→ * const spinner = new PhaseSpinner({
 12→ *   phase: 'exec',
 13→ *   phaseIndex: 2,
 14→ *   totalPhases: 3,
 15→ *   shutdownManager,
 16→ * });
 17→ *
 18→ * spinner.start();
 19→ * // ... phase execution
 20→ * spinner.succeed(); // Shows "✓ exec (2/3) (45s)"
 21→ * ```
 22→ */
 23→
 24→import { spinner as createSpinner, type SpinnerManager } from "./cli-ui.js";
 25→import type { ShutdownManager } from "./shutdown.js";
 26→
 27→/**
 28→ * Elapsed time update interval in milliseconds
 29→ */
 30→const ELAPSED_UPDATE_INTERVAL_MS = 5000;
 31→
 32→/**
 33→ * Options for creating a PhaseSpinner
 34→ */
 35→export interface PhaseSpinnerOptions {
 36→  /** Phase name (e.g., "spec", "exec", "qa") */
 37→  phase: string;
 38→  /** Current phase index (1-based) */
 39→  phaseIndex: number;
 40→  /** Total number of phases */
 41→  totalPhases: number;
 42→  /** Optional ShutdownManager for graceful cleanup */
 43→  shutdownManager?: ShutdownManager;
 44→  /** Optional prefix for indentation (default: "    ") */
 45→  prefix?: string;
 46→  /** Optional quality loop iteration (shows "iteration N" if > 1) */
 47→  iteration?: number;
 48→}
 49→
 50→/**
 51→ * Format elapsed time in human-readable format
 52→ *
 53→ * @param seconds - Elapsed time in seconds
 54→ * @returns Formatted string (e.g., "45s", "2m 15s", "1h 5m")
 55→ */
 56→export function formatElapsedTime(seconds: number): string {
 57→  if (seconds < 60) {
 58→    return `${Math.floor(seconds)}s`;
 59→  }
 60→  if (seconds < 3600) {
 61→    const minutes = Math.floor(seconds / 60);
 62→    const remainingSeconds = Math.floor(seconds % 60);
 63→    return remainingSeconds > 0
 64→      ? `${minutes}m ${remainingSeconds}s`
 65→      : `${minutes}m`;
 66→  }
 67→  const hours = Math.floor(seconds / 3600);
 68→  const remainingMinutes = Math.floor((seconds % 3600) / 60);
 69→  return remainingMinutes > 0 ? `${hours}h ${remainingMinutes}m` : `${hours}h`;
 70→}
 71→
 72→/**
 73→ * PhaseSpinner - Animated spinner with elapsed time and phase progress
 74→ *
 75→ * Features:
 76→ * - Animated spinner (or text fallback) via cli-ui
 77→ * - Elapsed time tracking with automatic updates
 78→ * - Phase progress indicator (e.g., "exec (2/3)")
 79→ * - ShutdownManager integration for graceful Ctrl+C cleanup
 80→ * - Pause/resume for verbose streaming output
 81→ */
 82→export class PhaseSpinner {
 83→  private spinner: SpinnerManager;
 84→  private startTime: number = 0;
 85→  private intervalId: ReturnType<typeof setInterval> | null = null;
 86→  private disposed = false;
 87→  private paused = false;
 88→
 89→  private readonly phase: string;
 90→  private readonly phaseIndex: number;
 91→  private readonly totalPhases: number;
 92→  private readonly shutdownManager?: ShutdownManager;
 93→  private readonly prefix: string;
 94→  private readonly iteration?: number;
 95→  private readonly cleanupName: string;
 96→
 97→  constructor(options: PhaseSpinnerOptions) {
 98→    this.phase = options.phase;
 99→    this.phaseIndex = options.phaseIndex;
100→    this.totalPhases = options.totalPhases;
101→    this.shutdownManager = options.shutdownManager;
102→    this.prefix = options.prefix ?? "    ";
103→    this.iteration = options.iteration;
104→    this.cleanupName = `phase-spinner-${options.phase}`;
105→
106→    // Create the underlying spinner with initial text
107→    this.spinner = createSpinner(this.formatText(0));
108→  }
109→
110→  /**
111→   * Format the spinner text with phase, progress, and elapsed time
112→   */
113→  private formatText(elapsedSeconds: number): string {
114→    const progress = `(${this.phaseIndex}/${this.totalPhases})`;
115→    const elapsed =
116→      elapsedSeconds > 0 ? ` ${formatElapsedTime(elapsedSeconds)}` : "";
117→    const iterationSuffix =
118→      this.iteration && this.iteration > 1
119→        ? ` [iteration ${this.iteration}]`
120→        : "";
121→
122→    return `${this.prefix}${this.phase} ${progress}...${elapsed}${iterationSuffix}`;
123→  }
124→
125→  /**
126→   * Update the spinner text with current elapsed time
127→   */
128→  private updateElapsedTime(): void {
129→    if (this.disposed || this.paused) return;
130→
131→    const elapsedSeconds = (Date.now() - this.startTime) / 1000;
132→    this.spinner.text = this.formatText(elapsedSeconds);
133→  }
134→
135→  /**
136→   * Start the spinner
137→   *
138→   * Begins the animation and elapsed time tracking.
139→   */
140→  start(): PhaseSpinner {
141→    if (this.disposed) return this;
142→
143→    this.startTime = Date.now();
144→    this.spinner.start(this.formatText(0));
145→
146→    // Start elapsed time update interval
147→    this.intervalId = setInterval(() => {
148→      this.updateElapsedTime();
149→    }, ELAPSED_UPDATE_INTERVAL_MS);
150→
151→    // Register with ShutdownManager for graceful cleanup
152→    if (this.shutdownManager) {
153→      this.shutdownManager.registerCleanup(this.cleanupName, async () => {
154→        this.stop();
155→      });
156→    }
157→
158→    return this;
159→  }
160→
161→  /**
162→   * Mark the phase as succeeded
163→   *
164→   * Stops the spinner and shows a checkmark with total duration.
165→   */
166→  succeed(customText?: string): PhaseSpinner {
167→    if (this.disposed) return this;
168→
169→    this.clearInterval();
170→    this.unregisterCleanup();
171→
172→    const elapsedSeconds = (Date.now() - this.startTime) / 1000;
173→    const duration = formatElapsedTime(elapsedSeconds);
174→    const progress = `(${this.phaseIndex}/${this.totalPhases})`;
175→    const text =
176→      customText ?? `${this.prefix}${this.phase} ${progress} (${duration})`;
177→
178→    this.spinner.succeed(text);
179→    this.disposed = true;
180→
181→    return this;
182→  }
183→
184→  /**
185→   * Mark the phase as failed
186→   *
187→   * Stops the spinner and shows an error indicator with message.
188→   */
189→  fail(error?: string): PhaseSpinner {
190→    if (this.disposed) return this;
191→
192→    this.clearInterval();
193→    this.unregisterCleanup();
194→
195→    const elapsedSeconds = (Date.now() - this.startTime) / 1000;
196→    const duration = formatElapsedTime(elapsedSeconds);
197→    const progress = `(${this.phaseIndex}/${this.totalPhases})`;
198→    const errorSuffix = error ? `: ${error}` : "";
199→    const text = `${this.prefix}${this.phase} ${progress} (${duration})${errorSuffix}`;
200→
201→    this.spinner.fail(text);
202→    this.disposed = true;
203→
204→    return this;
205→  }
206→
207→  /**
208→   * Stop the spinner without success/fail indication
209→   *
210→   * Use this for cleanup or when the phase is interrupted.
211→   */
212→  stop(): PhaseSpinner {
213→    if (this.disposed) return this;
214→
215→    this.clearInterval();
216→    this.unregisterCleanup();
217→    this.spinner.stop();
218→    this.disposed = true;
219→
220→    return this;
221→  }
222→
223→  /**
224→   * Pause the spinner (for verbose streaming output)
225→   *
226→   * Temporarily stops the animation without disposing.
227→   * Call resume() to continue.
228→   */
229→  pause(): PhaseSpinner {
230→    if (this.disposed || this.paused) return this;
231→
232→    this.paused = true;
233→    this.spinner.stop();
234→
235→    return this;
236→  }
237→
238→  /**
239→   * Resume the spinner after pause
240→   *
241→   * Restarts the animation with updated elapsed time.
242→   */
243→  resume(): PhaseSpinner {
244→    if (this.disposed || !this.paused) return this;
245→
246→    this.paused = false;
247→    const elapsedSeconds = (Date.now() - this.startTime) / 1000;
248→    this.spinner.start(this.formatText(elapsedSeconds));
249→
250→    return this;
251→  }
252→
253→  /**
254→   * Check if the spinner is currently active
255→   */
256→  get isSpinning(): boolean {
257→    return this.spinner.isSpinning && !this.disposed && !this.paused;
258→  }
259→
260→  /**
261→   * Get the total elapsed time in seconds
262→   */
263→  get elapsedSeconds(): number {
264→    if (this.startTime === 0) return 0;
265→    return (Date.now() - this.startTime) / 1000;
266→  }
267→
268→  /**
269→   * Dispose of the spinner and clean up resources
270→   *
271→   * Called automatically by succeed(), fail(), or stop().
272→   * Safe to call multiple times.
273→   */
274→  dispose(): void {
275→    if (this.disposed) return;
276→
277→    this.clearInterval();
278→    this.unregisterCleanup();
279→    this.spinner.stop();
280→    this.disposed = true;
281→  }
282→
283→  /**
284→   * Clear the elapsed time update interval
285→   */
286→  private clearInterval(): void {
287→    if (this.intervalId !== null) {
288→      clearInterval(this.intervalId);
289→      this.intervalId = null;
290→    }
291→  }
292→
293→  /**
294→   * Unregister from ShutdownManager
295→   */
296→  private unregisterCleanup(): void {
297→    if (this.shutdownManager) {
298→      this.shutdownManager.unregisterCleanup(this.cleanupName);
299→    }
300→  }
301→}
