303→/**
304→ * Create a PhaseSpinner with the given options
305→ *
306→ * Convenience function matching the pattern of cli-ui.spinner().
307→ */
308→export function phaseSpinner(options: PhaseSpinnerOptions): PhaseSpinner {
309→  return new PhaseSpinner(options);
